#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char s[200005];
    while(T--){
        scanf("%s",s);
        int n=strlen(s);
        int total=0, seen[26]={0};
        for(int i=0;i<n;i++) if(!seen[s[i]-'a']){ seen[s[i]-'a']=1; total++; }
        int cnt=0; memset(seen,0,sizeof(seen));
        int pos=0;
        for(int i=0;i<n;i++){
            if(!seen[s[i]-'a']){ seen[s[i]-'a']=1; cnt++; }
            if(cnt==total){ pos=i; break; }
        }
        s[pos+1]='\0';
        printf("%s\n",s);
    }
    return 0;
}

