            if(cnt==distinct){ pos=i; break; }
        }
        cout<<t.substr(0,pos+1) <<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            String t = br.readLine().trim();
            int n = t.length();
            boolean[] seenAll = new boolean[26];
            int distinct = 0;
            for (int i = 0; i < n; i++) {
                int idx = t.charAt(i) - 'a';
                if (!seenAll[idx]) { seenAll[idx] = true; distinct++; }
            }
            boolean[] seen = new boolean[26];
            int cnt = 0, pos = 0;
            for (int i = 0; i < n; i++) {
                int idx = t.charAt(i) - 'a';
                if (!seen[idx]) { seen[idx] = true; cnt++; }
                if (cnt == distinct) { pos = i; break; }
            }
            out.append(t.substring(0, pos + 1)).append('\n');
        }
        System.out.print(out.toString());
    }
}

