let res = [];
for (let tc = 0; tc < T; tc++) {
  const t = input[idx++];
  const distinct = new Set(t).size;
  const seen = new Set();
  let pos = 0;
  for (let i = 0; i < t.length; i++) {
    seen.add(t[i]);
    if (seen.size === distinct) { pos = i; break; }
  }
  res.push(t.slice(0, pos + 1));
}
